import Advice from '../advices/Advice';
import BuildingDetails from '../../buildings/BuildingDetails';
import buildingStore from '../../../stores/buildings/buildingStore';
import dataStore from '../../../stores/sensors/dataStore';
import comparisonBoardStore from '../../../stores/modules/comparisonBoardStore';
import reportingStore from '../../../stores/modules/reportingStore';
import sidebarStore from '../../../stores/sidebarStore';
import visualizationStore from '../../../stores/modules/visualizationStore';
import Loader from '../../shared/Loader';
import appStore from '/app/stores/appStore';
import {Chart as ChartJS} from 'chart.js/auto';
import {Bar, Line, Chart, Doughnut} from 'react-chartjs-2';
import ChartDatalabels from 'chartjs-plugin-datalabels';
import Button from 'app/components/sharedV2/Button';

const {dateApiFormat, dateUiFormat} = __.app;
const {cn, router, i18n, ui, moment, acl} = __;

class Reporting extends React.Component {
  constructor(props) {
    super(props);
    this.store = reportingStore;

    let dateBegin = moment().year(this.props.year);
    let dateEnd = moment().year(this.props.year);
    const month = this.props.month;

    if (month) {
      dateBegin = dateBegin.month(month - 1).date(1);
      dateEnd = dateEnd.month(month).date(1).subtract(1, 'day');
    } else {
      dateBegin = dateBegin.month(0).date(1);
      dateEnd = dateEnd.month(11).date(31);
    }

    this.state = {
      housingType: 'all',
      dateBegin,
      dateEnd,
      ...this.getState(),
    };
  }

  componentDidMount() {
    this.store.scope.listen(this._onStateChange);
    comparisonBoardStore.scope.listen(this._onStateChange);
    visualizationStore.scope.listen(this._onStateChange);
    dataStore.scope.listen(this._onStateChange);

    const {dateBegin, dateEnd, mainSensor} = this.state;
    const groupBy = this.props.month ? 'day' : 'month';

    if (mainSensor) {
      this.store.fetchAll({
        sensorId: mainSensor.id,
        dateBegin: dateBegin.format(dateApiFormat),
        dateEnd: dateEnd.format(dateApiFormat),
      });
      dataStore.setState({groupBy});
      dataStore.updateGeneralDates({dateBegin, dateEnd});
      if (this.isComparableSensorTag()) {
        this.retrieveBuildingProfile();
      }
    }
    sidebarStore.displayBuildingsList({
      showSensors: true,
      onClickSensor: (sensor) => {
        dataStore.toggleSingleDatumToDisplay(sensor);
        this.store.fetchAll({
          sensorId: sensor.id,
          dateBegin: dateBegin.format(dateApiFormat),
          dateEnd: dateEnd.format(dateApiFormat),
        });
      },
    });
    appStore.setAppTitle(i18n.t('Reporting.appTitle'));
  }

  componentWillUnmount() {
    this.store.scope.unlisten(this._onStateChange);
    comparisonBoardStore.scope.unlisten(this._onStateChange);
    visualizationStore.scope.unlisten(this._onStateChange);
    dataStore.scope.unlisten(this._onStateChange);
    sidebarStore.hideBuildingsList();

    // fromReporting is used to indicate if the previous route is reporting
    const route = router.getRoute('reporting');
    route.fromReporting = 0;
  }

  _onStateChange() {
    const oldMainSensor = this.state.mainSensor;
    this.setState(this.getState());
    const {dateBegin, dateEnd, mainSensor} = this.state;

    if (oldMainSensor == null && mainSensor && mainSensor.id != null) {
      this.store.fetchAll({
        sensorId: mainSensor.id,
        dateBegin: dateBegin.format(dateApiFormat),
        dateEnd: dateEnd.format(dateApiFormat),
      });
      if (this.isComparableSensorTag()) {
        this.retrieveBuildingProfile();
      }
    }
  }

  getState() {
    const state = {
      ...this.store.getState(),
      ...comparisonBoardStore.getState(),
      ...visualizationStore.getState(),
      ...dataStore.getState(),
    };
    return state;
  }

  retrieveBuildingProfile() {
    const component = this;
    const {dateBegin, dateEnd} = this.state;
    const mainSensor = this.state.mainSensor;
    if (mainSensor) {
      buildingStore.fetchBuildingProfile(mainSensor.buildingId).then((building) => {
        if (building.numberOccupants) {
          const housingType = building.housingType || component.state.housingType;
          const occupantNumber = building.numberOccupants < 6 ? String(building.numberOccupants) : '6+';
          comparisonBoardStore.fetchAll({
            nbHab: occupantNumber,
            typeHab: housingType,
            sensorTag: mainSensor.tags.find((tag) => tag.isComparable).name,
            dateBegin: dateBegin.format(dateApiFormat),
            dateEnd: dateEnd.format(dateApiFormat),
          });
        }
      });
    }
  }

  computeComfortConfig() {
    const {minValue, maxValue, ratios} = this.state;

    const config = {
      type: 'doughnut',
      data: {
        labels: [
          i18n.t('Reporting.comfort.ltValueLabel', {minValue}),
          i18n.t('Reporting.comfort.btwValuesLabel', {minValue, maxValue}),
          i18n.t('Reporting.comfort.gteValueLabel', {maxValue}),
        ],
        datasets: [
          {
            data: [ratios[0], ratios[1], ratios[2]],
            backgroundColor: ['#2196f3', '#ff9800', '#f70a0a'],
            circumference: 180,
            rotation: 270,
          },
        ],
      },
      options: {
        plugins: {
          datalabels: {
            display: true,
            align: 'end',
            anchor: 'end',
            color: 'black',
            font: {
              weight: 'bold',
            },
            formatter: (context, args) => {
              const indexLabels = args.dataIndex;
              return args.chart.data.labels[indexLabels];
            },
          },
          title: {
            display: true,
            text: i18n.t('Reporting.comfort.title', {
              dateBegin: this.state.dateBegin.format(dateUiFormat),
              dateEnd: this.state.dateEnd.format(dateUiFormat),
              interpolation: {escapeValue: false},
            }),
            color: '#5e5e5e',
            font: {
              size: '25rem',
            },
          },
          tooltip: {
            display: true,
            displayColors: false,
            titleColor: 'black',
            bodyColor: 'black',
            backgroundColor: 'rgba(206, 206, 206, .8)',
            borderWidth: 2,
            borderColor: (tooltipItem) => {
              return tooltipItem.tooltip.labelColors.backgroundColor;
            },
            callbacks: {
              label: function (tooltipItem, data) {
                const value = parseFloat(
                  config.data.datasets[tooltipItem.datasetIndex].data[tooltipItem.dataIndex].toFixed(1),
                );
                const labelString = `${value}%`;
                return labelString;
              },
            },
          },
          legend: {
            display: false,
          },
        },
        responsive: true,
        maintainAspectRatio: false,
      },
    };

    return config;
  }

  computeTickIntervall(nb) {
    return parseInt(nb / 50, 10);
  }

  _formatObjDataQuantity(groupBy, quantity, duration) {
    let formattedObjDataQuantity = null;
    let quantInDays = null;

    if (duration === 'month') {
      quantInDays = quantity / 30.5;
    } else {
      quantInDays = quantity / 365;
    }

    switch (groupBy) {
      case 'default': {
        formattedObjDataQuantity = (quantInDays / (24 * 6)).toFixed(2);
        break;
      }

      case 'hours': {
        formattedObjDataQuantity = (quantInDays / 24).toFixed(2);
        break;
      }

      case 'days': {
        formattedObjDataQuantity = quantInDays.toFixed(2);
        break;
      }

      case 'month': {
        formattedObjDataQuantity = (quantInDays * 30.5).toFixed(2);
        break;
      }

      case 'year': {
        formattedObjDataQuantity = (quantInDays * 365).toFixed(2);
        break;
      }

      default: {
        formattedObjDataQuantity = quantInDays.toFixed(2);
        break;
      }
    }

    return Number(formattedObjDataQuantity);
  }

  /**
   * Return the unit display on the y axis
   */
  getUnitAxis({unit, isAverage}) {
    const displayedValue = isAverage ? 'value' : this.state.displayedValue;

    switch (displayedValue) {
      case 'value':
        return unit;
      case 'value/hab':
        return unit + '/occupants';
      case 'money':
        return '€';
      case 'co2':
        return 'KgCO₂';
      default:
        return null;
    }
  }

  isComparableSensorTag() {
    const {mainSensor} = this.state;
    return mainSensor.tags.length > 0 && mainSensor.tags.some((tag) => tag.isComparable);
  }

  /**
   * Compute the config needed for chartjs to display graph
   */
  // TODO: try to reduce complexity
  // eslint-disable-next-line max-statements, complexity
  computeConsumptionConfig() {
    const {refObjective, displayedValue, groupBy} = this.state;
    const dataToDisplay = this.state.data;

    const config = {
      data: {
        labels: this.state.graphCategories,
        datasets: [],
      },
      options: {
        animation: {
          onComplete: () => {
            const delayed = true;
          },
          delay: (context) => {
            let delay = 0;
            const delayed = true;
            if (context.type === 'data' && context.mode === 'default' && !delayed) {
              delay = context.dataIndex * 500 + context.datasetIndex * 100;
              return delay;
            }
          },
        },
        scales: {
          y: [],
          x: [],
        },
        plugins: {
          legend: {
            display: false,
          },
          tooltip: [],
        },
        responsive: true,
        maintainAspectRatio: false,
      },
    };

    // Add series and y axes
    const yAxes = [];
    let unitAxis = '';

    for (const key in dataToDisplay) {
      const datum = dataToDisplay[key];

      // Format each data based on the groupBy value
      let data = [];

      if (groupBy === 'default') {
        data = datum.formattedData.map((d) => {
          const temp = d.value;
          return temp;
        });
      } else {
        data = datum.formattedData.map((d) => {
          const temp = d.value;
          return temp;
        });
      }

      // Check if an yAxis for the dataType associated to this serie already exists
      // if not then it is created
      const yAxisAvailable = yAxes.filter((axis) => {
        return axis.dataTypeId === dataToDisplay[key].dataTypeId;
      });

      let yIndex = null;
      if (yAxisAvailable.length > 0) {
        yIndex = yAxes.indexOf(yAxisAvailable[0]);
      } else {
        const dataType = this.getDataType(dataToDisplay[key].dataTypeId);
        let legendName = i18n.t('store.dataTypes.name.' + dataType.name, {
          defaultValue: dataType.name,
        });

        if (this.props.displayedValue === 'money' && !dataType.isAverage) {
          legendName = i18n.t('Reporting.money');
        } else if (this.state.displayedValue === 'co2') {
          legendName = 'co2';
        }

        unitAxis = this.getUnitAxis({
          unit: dataType.unit,
          isAverage: dataType.isAverage,
        });

        config.options.scales.y = {
          grace: '60%',
          position: yAxes.length > 0 ? 'right' : 'left',
          title: {
            display: true,
            text: legendName,
            color: dataToDisplay[key].config.color,
          },
          ticks: {
            callback: (v) => v + ' ' + unitAxis,
            stepSize: this.computeTickIntervall(this.state.graphCategories.length),
          },
        };

        config.options.scales.x = {
          type: groupBy === 'default' ? 'time' : 'category',
          stacked: true,
          grid: {
            display: false,
          },
        };

        yIndex = yAxes.length - 1;
      }

      const serieGeneral = {
        label: this.state.mainSensor.name,
        data,
        type: this.state.data[0].config.graphType,
        borderColor: datum.config.color,
        backgroundColor: datum.config.color,
      };

      config.data.datasets.push(serieGeneral);
    }

    if (refObjective && dataToDisplay && displayedValue === 'value' && groupBy !== 'default') {
      const yAxisAvailable = yAxes.filter((axis) => {
        return axis.dataTypeId === dataToDisplay[0].dataTypeId;
      });
      const yIndex = yAxes.indexOf(yAxisAvailable[0]);

      const formatRefObj = refObjective.map((d) => d.value);

      const serieObjective = {
        type: 'line',
        data: formatRefObj,
        label: i18n.t('Dashboard.objectiveTitle'),
        borderColor: '#4CAF50',
        backgroundColor: '#4CAF50',
        order: -1,
      };

      config.data.datasets.push(serieObjective);

      config.options.plugins.tooltip = {
        yAlign: 'bottom',
        intersect: true,
        displayColors: false,
        titleColor: 'black',
        bodyColor: 'black',
        backgroundColor: 'rgba(206, 206, 206, .8)',
        borderWidth: 2,
        borderColor: (tooltipItem) => {
          if (tooltipItem.tooltipItems[0]) {
            return tooltipItem.tooltipItems[0].dataset.backgroundColor;
          }
        },
        callbacks: {
          label: function (tooltipItem, data) {
            // Get the label name and value based on the dataset index and tooltip index
            const labelName = config.data.datasets[tooltipItem.datasetIndex].label;
            const value = parseFloat(
              config.data.datasets[tooltipItem.datasetIndex].data[tooltipItem.dataIndex].toFixed(1),
            );
            const unitGraph = unitAxis;
            const labelString = `${labelName} : ${value} ${unitGraph} `;
            return labelString;
          },
        },
      };
    }

    return config;
  }

  getDataTypeCss(dataType) {
    switch (dataType.name) {
      case 'electricity':
        return 'fa-plug';
      case 'water':
        return 'fa-tint';
      case 'temperature':
        return 'fa-thermometer-three-quarters';
      default:
        return 'fa-cloud';
    }
  }

  retrieveUnitPrice() {
    let unitPrice = null;
    const {data} = this.state;
    const datumToDisplay = data[0];
    if (datumToDisplay.data && datumToDisplay.data.length > 0) {
      const totalMoney = datumToDisplay.data.reduce((total, d) => total + Number(d.money), 0);
      const totalValue = Number(datumToDisplay.totalCleanedValue);
      if (totalValue > 0) {
        unitPrice = Number(totalMoney / totalValue);
      }
    }
    return unitPrice;
  }

  /**
   * Retreive dataType associated to the given dataTypeId
   */
  getDataType(dataTypeId) {
    if (dataTypeId in this.state.dataTypes) {
      const dataType = this.state.dataTypes[dataTypeId];
      return dataType;
    }

    throw new Error('There is no associated data type with the id ' + dataTypeId);
  }

  displayObjectives() {
    this.setState({isObjectiveDisplayed: !this.state.isObjectiveDisplayed});

    // Manage alerts of data quantity errors for the objective display
    if (this.state.displayDataQuantError && !this.state.isObjectiveDisplayed) {
      ui.notifyError(i18n.t('alerts.maxDataQuantError'));
    }
  }

  // TODO: add comments
  // eslint-disable-next-line max-statements
  computeComparisonConfig() {
    // Retrieve unit price
    const unitPrice = this.retrieveUnitPrice();

    const mainSensor = this.state.mainSensor;
    const dataType = this.getDataType(mainSensor.dataTypeId);

    const catagoriesLabels = [
      i18n.t('ComparisonBoard.categories.myData', {
        buildingDisplayName: i18n.building,
      }),
      i18n.t('ComparisonBoard.categories.globalAverage'),
    ];

    const config = {
      type: 'bar',
      data: {
        labels: catagoriesLabels,
        datasets: [],
      },
      options: {
        indexAxis: 'y',
        scales: [],
        plugins: {
          tooltip: [],
          legend: {
            display: false,
          },
        },
      },
    };

    const yAxes = [];

    const unitAxis = unitPrice == null ? dataType.unit : '€';
    const legendName = i18n.t('store.dataTypes.name.' + dataType.name, {
      defaultValue: dataType.name,
    });

    yAxes.push({
      title: {
        display: true,
        text: legendName,
        color: 'black',
        padding: 20,
      },
      ticks: {
        callback: (v) => v.toFixed(0) + ' ' + unitAxis,
      },
    });

    const totalValue = this.getTotalValue();
    const neighborsaverageValue = this.state.neighborsComparison ? this.state.neighborsComparison.averageValue : 0;
    const ancestorBuildingaverageValue = this.state.ancestorBuildingComparison
      ? this.state.ancestorBuildingComparison.averageValue
      : 0;
    const serie = {
      type: 'bar',
      data: [
        {
          label: i18n.t('ComparisonBoard.categories.myData', {
            buildingDisplayName: i18n.building,
          }),
          backgroundColor: '#66bb6a',
          borderColor: '#66bb6a',
          data: unitPrice == null ? Number(totalValue.toFixed()) : Number((totalValue * unitPrice).toFixed()),
        },
        {
          label: i18n.t('ComparisonBoard.categories.globalAverage'),
          backgroundColor: '#a9a9a9',
          borderColor: '#a9a9a9',
          data:
            unitPrice === null
              ? Number(neighborsaverageValue.toFixed())
              : Number((neighborsaverageValue * unitPrice).toFixed()),
        },
      ],
    };

    if (ancestorBuildingaverageValue) {
      config.data.labels.splice(1, 0, i18n.t('ComparisonBoard.categories.neighborsAverage'));
      serie.data.splice(1, 0, {
        label: i18n.t('ComparisonBoard.categories.neighborsAverage'),
        backgroundColor: '#5e5e5e',
        data:
          unitPrice === null
            ? Number(ancestorBuildingaverageValue.toFixed())
            : Number((ancestorBuildingaverageValue * unitPrice).toFixed()),
      });
    }

    config.options.plugins.tooltip = {
      yAlign: 'bottom',
      intersect: true,
      displayColors: false,
      titleColor: 'black',
      bodyColor: 'black',
      backgroundColor: 'rgba(206, 206, 206, .8)',
      borderWidth: 2,
      borderColor: (tooltipItem) => {
        if (tooltipItem.tooltipItems[0]) {
          return tooltipItem.tooltipItems[0].dataset.backgroundColor;
        }
      },
      callbacks: {
        label: function (tooltipItem, data) {
          // Get the label name and value based on the dataset index and tooltip index
          const labelName = config.data.datasets[tooltipItem.datasetIndex].label;
          const value = parseFloat(
            config.data.datasets[tooltipItem.datasetIndex].data[tooltipItem.dataIndex].toFixed(1),
          );
          const unitGraph = unitAxis;
          const labelString = `${labelName} : ${value} ${unitAxis} `;
          return labelString;
        },
      },
    };

    config.data.datasets.push(serie);
    config.options.plugins.title = {
      text: i18n.t('ComparisonBoard.graphTitle'),
      color: '#5e5e5e',
      font: {
        size: '3rem',
      },
    };
    config.options.scales.x = {
      display: false,
    };

    return config;
  }

  getTotalValue() {
    const totalValue =
      this.state.data && this.state.data.length > 0 && this.state.data[0].totalCleanedValue != null
        ? Number(this.state.data[0].totalCleanedValue)
        : 0;
    return totalValue;
  }

  computeDaysAboveThreshold(type) {
    if (!this.state.mainSensor.thresholds) {
      return null;
    }

    const threshold =
      type === 'critical' ? this.state.mainSensor.thresholds.critical : this.state.mainSensor.thresholds.avg;
    let nbDays = 0;

    if (this.state.data.length === 0) {
      return '-';
    }

    this.state.data[0].data.forEach(function ({value}) {
      if (Number(value) > threshold) nbDays += 1;
    });

    return nbDays;
  }

  renderWrapper(content) {
    return (
      <section id='content'>
        <div className='container'>{content}</div>
      </section>
    );
  }

  // TODO: split into several render to reduce max statements and improve lisibility
  // eslint-disable-next-line max-statements,complexity
  renderConsumptionBoard() {
    let content = null;
    let objectiveComparisonMessage = null;
    const {refObjective, data} = this.state;
    const datumToDisplay = data[0];

    if (datumToDisplay.data === null || datumToDisplay.data.length === 0) {
      return null;
    }
    // Retrieve unit price
    const unitPrice = this.retrieveUnitPrice();
    // Retrive datatype unit
    const dataType = this.getDataType(datumToDisplay.dataTypeId);
    const dataTypeCssClass = this.getDataTypeCss(dataType);
    const unitAxis = this.getUnitAxis({
      unit: dataType.unit,
      isAverage: dataType.isAverage,
    });
    const totalMoney = datumToDisplay.data.reduce((total, d) => total + Number(d.money), 0);
    const totalValue = this.getTotalValue();

    // manage reference objective
    if (refObjective && refObjective.length > 0) {
      const objectiveValue = refObjective[0].value;

      if (objectiveValue > 0 && datumToDisplay.data.length > 0) {
        // Compute the percentage of the diff of consumption (diffRatio)
        const objectiveTotalValue = refObjective.reduce((total, d) => total + Number(d.value), 0);
        const objectiveTotalMoney = objectiveTotalValue * unitPrice;
        const diffValue = objectiveTotalValue - totalValue;
        const diffMoney = objectiveTotalMoney - totalMoney;
        const objectiveComparisonMessageKey = this.props.month
          ? 'Reporting.consumption.monthlyObjectiveValueText'
          : 'Reporting.consumption.yearlyObjectiveValueText';
        objectiveComparisonMessage = (
          <div>
            <p>
              {i18n.t(objectiveComparisonMessageKey, {
                objectiveTotalValue: objectiveTotalValue.toFixed(),
                objectiveTotalMoney: objectiveTotalMoney.toFixed(2),
                unitAxis,
              })}
            </p>

            {diffValue > 0 ? (
              <div>
                <p>
                  {i18n.t('Reporting.consumption.savingsValueText', {
                    diffValue: diffValue.toFixed(),
                    unitAxis,
                  })}
                </p>
                <p>
                  {i18n.t('Reporting.consumption.savingsMoneyText', {
                    diffMoney: diffMoney.toFixed(2),
                  })}
                </p>
              </div>
            ) : (
              <div>
                <p>
                  {i18n.t('Reporting.consumption.expensesValueText', {
                    diffValue: (diffValue * -1).toFixed(),
                    unitAxis,
                  })}
                </p>
                <p>
                  {i18n.t('Reporting.consumption.expensesMoneyText', {
                    diffMoney: (diffMoney * -1).toFixed(2),
                  })}
                </p>
              </div>
            )}
          </div>
        );
      }
    }

    content = (
      <div>
        <p className='txt-c'>
          {i18n.t('Reporting.consumption.dateRangeText', {
            dateBegin: this.state.dateBegin.format(dateUiFormat),
            dateEnd: this.state.dateEnd.format(dateUiFormat),
            type: dataType.isAverage
              ? i18n.t('Reporting.consumption.type.average')
              : i18n.t('Reporting.consumption.type.consumption'),
            interpolation: {escapeValue: false},
          })}
        </p>
        <div className='p-1 card f-item f-flex1'>
          <p className='f-between f-align-center'>
            <i className={cn('fa icon lg', dataTypeCssClass)} />
            <span
              className='text-30 txt-c'
              style={{fontWeight: '700'}}
            >
              {totalValue.toFixed()} {unitAxis}
            </span>
          </p>
          {this.state.mode === 'standard' && !dataType.isAverage && totalMoney > 0 && (
            <p className='f-between f-align-center'>
              <i className='fa fa-money icon lg' />
              <span
                className='text-30 txt-c'
                style={{fontWeight: '700'}}
              >
                {totalMoney.toFixed()} {i18n.t('Reporting.money')}*
              </span>
            </p>
          )}
        </div>
        {this.state.mode === 'standard' && totalMoney > 0 && <p>{i18n.t('Reporting.consumption.costDetailText')}</p>}
        {objectiveComparisonMessage}
        {this.state.mode === 'qai' && (
          <>
            <p>
              {i18n.t('Reporting.nbDaysAboveAverage', {
                value: this.computeDaysAboveThreshold('avg'),
              })}
            </p>
            <p>
              {i18n.t('Reporting.nbDaysAboveCritical', {
                value: this.computeDaysAboveThreshold('critical'),
              })}
            </p>
          </>
        )}
      </div>
    );
    return content;
  }

  // TODO: reduce complexity
  // eslint-disable-next-line complexity
  render() {
    if (this.state.isDataLoading || this.state.isLoading) {
      return this.renderWrapper(<Loader />);
    }

    const comfortConfig = this.state.ratios ? this.computeComfortConfig() : null;
    const consumptionConfig = this.state.data.length > 0 ? this.computeConsumptionConfig() : null;
    const comparisonConfig =
      this.state.mainSensor && this.isComparableSensorTag() && this.getTotalValue()
        ? this.computeComparisonConfig()
        : null;
    const mainSensor = this.state.mainSensor;

    const content = (
      <div>
        {
