handleBeforePrint() {
  const isLandscape = window.matchMedia('(orientation: landscape)').matches;
  const SAFE_PRINT_WIDTH = isLandscape ? 1122 : 718;

  const charts = Chart.getChart();
  if (charts) {
    charts.forEach(chart => {
      const aspectRatio = 16/9; // or whatever ratio you prefer
      const height = SAFE_PRINT_WIDTH / aspectRatio;

      chart.resize(SAFE_PRINT_WIDTH, height);
      chart.options = {
        ...chart.options,
        responsive: true,
        maintainAspectRatio: false,
        plugins: {
          ...chart.options.plugins,
          legend: {
            ...chart.options.plugins.legend,
            position: isLandscape ? 'right' : 'bottom'
          }
        }
      };

      chart.update('none');
    });
  }
}
